  Future<String> _uploadFileToS3(String fileName, List<int> fileBytes) async {
    final contentType = 'image/jpeg';
    final url = 'https://$_s3Bucket.s3.$_s3Region.amazonaws.com/$fileName';
    
    final now = DateTime.now().toUtc();
    final dateStamp = DateFormat('yyyyMMdd').format(now);
    final amzDate = DateFormat("yyyyMMdd'T'HHmmss'Z'").format(now);
    
    final credentialScope = '$dateStamp/$_s3Region/s3/aws4_request';
    
    final canonicalRequest = _createCanonicalRequest(
      'PUT',
      '/$fileName',
      '',
      {
        'host': '$_s3Bucket.s3.$_s3Region.amazonaws.com',
        'x-amz-date': amzDate,
        'x-amz-content-sha256': sha256.convert(fileBytes).toString(),
      },
      sha256.convert(fileBytes).toString(),
    );
    
    final stringToSign = _createStringToSign(
      amzDate,
      credentialScope,
      canonicalRequest,
    );
    
    final signingKey = _getSignatureKey(_awsSecretKey, dateStamp, _s3Region, 's3');
    final signature = _hmacSha256(signingKey, utf8.encode(stringToSign));
    
    final authorization = 'AWS4-HMAC-SHA256 Credential=$_awsAccessKey/$credentialScope, SignedHeaders=host;x-amz-content-sha256;x-amz-date, Signature=${_bytesToHex(signature)}';
    
    final response = await http.put(
      Uri.parse(url),
      headers: {
        'Host': '$_s3Bucket.s3.$_s3Region.amazonaws.com',
        'x-amz-date': amzDate,
        'x-amz-content-sha256': sha256.convert(fileBytes).toString(),
        'Authorization': authorization,
        'Content-Type': contentType,
      },
      body: fileBytes,
    );
    
    if (response.statusCode != 200) {
      throw Exception('S3 upload failed: ${response.statusCode} - ${response.body}');
    }
    
    return url;
  }

  String _createCanonicalRequest(
    String method,
    String uri,
    String queryString,
    Map<String, String> headers,
    String payloadHash,
  ) {
    final sortedHeaders = headers.keys.toList()..sort();
    final canonicalHeaders = sortedHeaders.map((key) => '${key.toLowerCase()}:${headers[key]}\n').join();
    final signedHeaders = sortedHeaders.map((key) => key.toLowerCase()).join(';');
    
    return '$method\n$uri\n$queryString\n$canonicalHeaders\n$signedHeaders\n$payloadHash';
  }

  String _createStringToSign(String amzDate, String credentialScope, String canonicalRequest) {
    final hashedCanonicalRequest = sha256.convert(utf8.encode(canonicalRequest)).toString();
    return 'AWS4-HMAC-SHA256\n$amzDate\n$credentialScope\n$hashedCanonicalRequest';
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmacSha256(utf8.encode('AWS4$key'), utf8.encode(dateStamp));
    final kRegion = _hmacSha256(kDate, utf8.encode(regionName));
    final kService = _hmacSha256(kRegion, utf8.encode(serviceName));
    final kSigning = _hmacSha256(kService, utf8.encode('aws4_request'));
    return kSigning;
  }

  List<int> _hmacSha256(List<int> key, List<int> data) {
    final hmac = Hmac(sha256, key);
    return hmac.convert(data).bytes;
  }

  String _bytesToHex(List<int> bytes) {
    return bytes.map((byte) => byte.toRadixString(16).padLeft(2, '0')).join();
  }

